(function() {
    console.log("কীবোর্ড সিমুলেশন মোড অ্যাক্টিভ! 🚀");

    // ১. মানুষের মতো টাইপিং সিমুলেট করার ফাংশন
    async function typeLikeHuman(element, text) {
        element.focus();
        for (let char of text) {
            // প্রতিটি ক্যারেক্টারের জন্য ইভেন্ট তৈরি
            const opts = { bubbles: true, cancelable: true, key: char, charCode: char.charCodeAt(0) };

            element.dispatchEvent(new KeyboardEvent('keydown', opts));
            element.dispatchEvent(new KeyboardEvent('keypress', opts));

            // টেক্সট যোগ করা
            if (element.tagName === 'DIV') element.innerText += char;
            else element.value += char;

            element.dispatchEvent(new Event('input', { bubbles: true }));
            element.dispatchEvent(new KeyboardEvent('keyup', opts));

            // টাইপিংয়ের মাঝে সামান্য বিরতি (মানুষের মতো গতি)
            await new Promise(resolve => setTimeout(resolve, 
30)); 
        }
    }

    // ২. প্রথম স্ক্রিন পূরণ
    async function runStep1() {
        const fname = document.getElementById('fname');
        const lname = document.getElementById('lname');
        const nextBtn = document.querySelector('#screen1 .btn-next');

        if (fname && lname) {
            await typeLikeHuman(fname, "Axiom,A Bot!(For Atomation)");
            await typeLikeHuman(lname, "Browser");

            setTimeout(() => {
                nextBtn.click();
                setTimeout(runStep2, 1000); // ২য় স্ক্রিনে যাওয়ার জন্য ১ সেকেন্ড বিরতি
            }, 900);
        }
    }

    // ৩. দ্বিতীয় স্ক্রিন পূরণ
    async function runStep2() {
        const cname = document.getElementById('cname');
        const pass = document.getElementById('pass');
        const finishBtn = document.querySelector('#screen2 .btn-next');

        if (cname && pass) {
            await typeLikeHuman(cname, "OpenDeta");
            await typeLikeHuman(pass, "123456");

            setTimeout(() => {
                finishBtn.click();
                console.log("সব ধাপ কীবোর্ড দিয়ে টাইপ করা হয়েছে! 🎉");
            }, 900);
        }
    }

    // ৪. স্টার্ট
    runStep1();

})();
